    let max_num = *nums.iter().max().unwrap() as usize;
    let is_prime = vec![true; max_num + 1];
    is_prime[0] = false;
    is_prime[1] = false;
    for i in 2..=max_num {
        if is_prime[i] {
            for j in i * i..=max_num {
                is_prime[j] = false;
            }
        }
    }

    // BFS to find the minimum number of jumps
    let mut queue = VecDeque::new();
    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;
    queue.push_back(0);

    while let Some(i) = queue.pop_front() {
